SELECT DISTINCT ?provinceLabel WHERE {
  ?player p:P161 [
    ps:P161 wd:Q1059484;
    pq:P580 "2019-07-26"^^xsd:date
  ].
  ?player p:P161 [
    ps:P161 ?previousClub;
    pq:P582 ?endDate
  ].
  FILTER (?endDate < "2019-07-26"^^xsd:date).
  ?previousClub wdt:P131 ?province.
  OPTIONAL { ?province rdfs:label ?provinceLabel. FILTER (lang(?provinceLabel) = "en") }
}

